package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

import java.util.ArrayList;
import java.util.List;
import java.util.Set;
import java.util.concurrent.atomic.AtomicInteger;

import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.dsl.RuleCompiler;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.dsl.StandardRuleSpecs;
import org.junit.jupiter.api.Test;

class RuleRegistryTest {

	@Test
	void rejectsDuplicateRuleIds() {
		IllegalArgumentException error = assertThrows(IllegalArgumentException.class,
				() -> RuleRegistry.builder()
						.add(new StandardCascadesRules.JoinCommutationRule())
						.add(new StandardCascadesRules.JoinCommutationRule())
						.build());

		assertEquals("Duplicate Cascades rule id: join-commute", error.getMessage());
	}

	@Test
	void evaluatesMatchingOperatorAndWildcardBucketsInRegistrationOrder() {
		List<String> matches = new ArrayList<>();
		List<String> telemetry = new ArrayList<>();
		RuleRegistry registry = RuleRegistry.builder()
				.add(new TrackingRule("join-only", RuleRootOperator.JOIN, matches))
				.add(new TrackingRule("filter-only", RuleRootOperator.FILTER, matches))
				.add(new TrackingRule("wildcard", RuleRootOperator.WILDCARD, matches))
				.build();
		MemoExpr expression = MemoExpr.logical(1, 1,
				new Join(pattern("s", "p1", "o"), pattern("o", "p2", "x")), List.of(), "");
		CascadesTelemetry recording = new CascadesTelemetry() {
			@Override
			public void ruleEvaluated(MemoExpr evaluated, CascadesRule rule, OptimizationGoal goal, boolean matched,
					int promise, String status) {
				telemetry.add(rule.id() + ':' + status);
			}
		};

		List<String> applicable = registry.applicableRules(expression, OptimizationGoal.root(), null, recording)
				.stream()
				.map(CascadesRule::id)
				.toList();

		assertEquals(List.of("join-only", "wildcard"), matches);
		assertEquals(List.of("join-only:matched", "filter-only:not_matched", "wildcard:matched"), telemetry);
		assertEquals(List.of("join-only", "wildcard"), applicable);
	}

	@Test
	void compiledRuleDescriptorUsesPatternRootOperator() {
		CascadesRule rule = RuleCompiler.compile(StandardRuleSpecs.joinCommute());

		assertEquals(Set.of(RuleRootOperator.JOIN), rule.descriptor().rootOperators());
		assertEquals(Set.of(RuleWakeUpEvent.LOGICAL_EXPRESSION_ADDED,
				RuleWakeUpEvent.REQUIRED_PROPERTIES_CHANGED), rule.descriptor().wakeUpEvents());
	}

	@Test
	void repeatedMatchingReusesRegisteredDescriptor() {
		AtomicInteger descriptorCalls = new AtomicInteger();
		RuleRegistry registry = RuleRegistry.builder()
				.add(new DescriptorCountingRule(descriptorCalls))
				.build();
		MemoExpr expression = MemoExpr.logical(1, 1,
				new Join(pattern("s", "p1", "o"), pattern("o", "p2", "x")), List.of(), "");

		for (int index = 0; index < 100; index++) {
			registry.applicableRules(expression, OptimizationGoal.root(), null);
		}

		assertEquals(1, descriptorCalls.get(),
				"Rule descriptors are immutable registration metadata and must not be rebuilt on the match hot path");
	}

	private static StatementPattern pattern(String subject, String predicate, String object) {
		return new StatementPattern(new Var(subject), new Var(predicate), new Var(object));
	}

	private record TrackingRule(String id, RuleRootOperator rootOperator, List<String> matches)
			implements FiniteTestCascadesRule {

		@Override
		public RuleDescriptor descriptor() {
			if (rootOperator == RuleRootOperator.WILDCARD) {
				return FiniteTestCascadesRule.super.descriptor();
			}
			return RuleDescriptor.builder(id, RuleKind.TRANSFORMATION)
					.rootOperators(rootOperator)
					.convergenceClass(RuleConvergenceClass.FINITE_EQUIVALENCE_EXPANSION)
					.build();
		}

		@Override
		public RuleKind kind() {
			return RuleKind.TRANSFORMATION;
		}

		@Override
		public boolean matches(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			matches.add(id);
			return true;
		}

		@Override
		public int promise(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return 1;
		}

		@Override
		public List<RuleApplication> apply(MemoExpr expression, OptimizationGoal goal, RuleContext context) {
			return List.of();
		}
	}

	private record DescriptorCountingRule(AtomicInteger descriptorCalls) implements FiniteTestCascadesRule {

		@Override
		public String id() {
			return "descriptor-counting";
		}

		@Override
		public RuleKind kind() {
			return RuleKind.IMPLEMENTATION;
		}

		@Override
		public RuleDescriptor descriptor() {
			descriptorCalls.incrementAndGet();
			return RuleDescriptor.builder(id(), kind())
					.rootOperators(RuleRootOperator.JOIN)
					.convergenceClass(RuleConvergenceClass.FINITE_EQUIVALENCE_EXPANSION)
					.build();
		}

		@Override
		public boolean matches(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return true;
		}

		@Override
		public int promise(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return 1;
		}

		@Override
		public List<RuleApplication> apply(MemoExpr expression, OptimizationGoal goal, RuleContext context) {
			return List.of();
		}
	}
}
